mapper.select:
select definition_id as definitionId, model_id as modelId, definition_key as definitionKey, definition_name as definitionName, definition_version as definitionVersion, category_name_snapshot as categoryNameSnapshot, form_name_snapshot as formNameSnapshot, lifecycle_state as lifecycleState, start_state as startState, published_by_name_snapshot as publishedByNameSnapshot, published_at as publishedAt from t_bpm_definition where 1 = 1
and definition_key like concat('%', #{queryForm.definitionKey}, '%')
and definition_name like concat('%', #{queryForm.definitionName}, '%')
and lifecycle_state = #{queryForm.lifecycleState}
and start_state = #{queryForm.startState}
order by published_at desc, definition_id desc

select max(definition_version)
from t_bpm_definition
where definition_key = #{definitionKey}
